-- Seed shift 715102 PM run with full turn-by-turn waypoints + road-following polyline.
--
-- Source: docs/runsheet-715102-pm.md and docs/runsheet-715102-pm-coords.md.
-- Coords picked by Mandeep from satellite imagery, verified on a live PM run on 2026-04-27.
-- Road polyline computed via OSRM public router (router.project-osrm.org), 19.71 km / 27 min.
--
-- This migration is idempotent for the route row and route_stops via UPSERT on
-- (route_id, sequence). It will NOT delete leftover rows with sequence > 24 that
-- predate this seed — if the route already had more rows than this, clean them up
-- manually first (mind the FK from stop_events with ON DELETE RESTRICT).
--
-- Note: turn waypoint #8 ("Right into Commercial Road") is intentionally NOT on the
-- visual road polyline. Including it in the OSRM request caused a 1.5 km westward
-- detour through Merbein P-10 grounds because OSRM treated the Mead/Commercial
-- corner as a strict checkpoint. The auto-advance trigger (PR #1) still fires when
-- the bus crosses the coord — `route_stops` rows drive nav logic; `path_geojson`
-- is purely cosmetic for the in-app map.

DO $migration$
DECLARE
  pm_route_id uuid;
BEGIN
  -- 1. Upsert the route row. If 715102-PM already exists, just bump version + description.
  INSERT INTO drivermate.routes (route_number, display_number, description, active, locked, version)
  VALUES (
    '715102-PM',
    '712 PM',
    'PM run · OL Sacred Heart → Merbein P-10 → St Joseph''s Stadium → Deakin & 11th. 4 stops, 20 turn waypoints, 19.71 km service section.',
    true,
    false,
    1
  )
  ON CONFLICT (route_number) DO UPDATE
    SET description = EXCLUDED.description,
        display_number = EXCLUDED.display_number,
        active = true,
        version = drivermate.routes.version + 1,
        updated_at = now()
  RETURNING id INTO pm_route_id;

  -- 2. Upsert the 24 route_stops by (route_id, sequence). Existing IDs preserved
  --    so any historical stop_events keep referencing valid rows.
